import React, { useState } from "react";
import {
  Button,
  Typography,
  Box,
  Grid,
  TextField,
} from "@mui/material";
import PhotoCamera from "@mui/icons-material/PhotoCamera";
import UploadFileIcon from "@mui/icons-material/UploadFile";

export default function DocumentUpload() {
  const [form, setForm] = useState({
    licenseNumber: "",
    rcNumber: "",
    insuranceNumber: "",
    aadharFront: null,
    aadharBack: null,
    licenseImage: null,
    rcImage: null,
    insuranceImage: null,
  });

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleFile = (field, file) => {
    setForm({ ...form, [field]: file });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log("📌 Submitted data:", form);
  };

  return (
    <Box sx={{ p: 4 }}>
      <Typography
        variant="h4"
        sx={{ textAlign: "center", fontWeight: "bold", mb: 4 }}
      >
        Upload Documents
      </Typography>

      <form onSubmit={handleSubmit}>
        <Grid container spacing={4}>
          {/* Left Column - Input Fields */}
          <Grid item xs={12} md={6}>
            <Box sx={{ display: "flex", flexDirection: "column", gap: 3 }}>
              <TextField
                label="License Number"
                name="licenseNumber"
                value={form.licenseNumber}
                onChange={handleChange}
                fullWidth
              />
              <TextField
                label="RC Number"
                name="rcNumber"
                value={form.rcNumber}
                onChange={handleChange}
                fullWidth
              />
              <TextField
                label="Insurance Policy Number"
                name="insuranceNumber"
                value={form.insuranceNumber}
                onChange={handleChange}
                fullWidth
              />
              <TextField
                label="Aadhar Card Front Number"
                name="aadharFrontNumber"
                value={form.aadharFrontNumber || ""}
                onChange={handleChange}
                fullWidth
              />
              <TextField
                label="Aadhar Card Back Number"
                name="aadharBackNumber"
                value={form.aadharBackNumber || ""}
                onChange={handleChange}
                fullWidth
              />
            </Box>
          </Grid>

          {/* Right Column - Upload Fields */}
          <Grid item xs={12} md={6}>
            <Box sx={{ display: "flex", flexDirection: "column", gap: 3 }}>
              {/* License */}
              <Typography variant="subtitle1">License Image</Typography>
              <Button
                component="label"
                variant="outlined"
                startIcon={<UploadFileIcon />}
              >
                Upload License
                <input
                  type="file"
                  hidden
                  onChange={(e) =>
                    handleFile("licenseImage", e.target.files[0])
                  }
                />
              </Button>
              {form.licenseImage && (
                <Typography variant="body2">
                  📂 {form.licenseImage.name}
                </Typography>
              )}
              <Button
                variant="contained"
                color="secondary"
                startIcon={<PhotoCamera />}
              >
                Use Camera
              </Button>

              {/* RC */}
              <Typography variant="subtitle1" sx={{ mt: 2 }}>
                RC Image
              </Typography>
              <Button
                component="label"
                variant="outlined"
                startIcon={<UploadFileIcon />}
              >
                Upload RC
                <input
                  type="file"
                  hidden
                  onChange={(e) => handleFile("rcImage", e.target.files[0])}
                />
              </Button>
              {form.rcImage && (
                <Typography variant="body2">📂 {form.rcImage.name}</Typography>
              )}
              <Button
                variant="contained"
                color="secondary"
                startIcon={<PhotoCamera />}
              >
                Use Camera
              </Button>

              {/* Insurance */}
              <Typography variant="subtitle1" sx={{ mt: 2 }}>
                Insurance Image
              </Typography>
              <Button
                component="label"
                variant="outlined"
                startIcon={<UploadFileIcon />}
              >
                Upload Insurance
                <input
                  type="file"
                  hidden
                  onChange={(e) =>
                    handleFile("insuranceImage", e.target.files[0])
                  }
                />
              </Button>
              {form.insuranceImage && (
                <Typography variant="body2">
                  📂 {form.insuranceImage.name}
                </Typography>
              )}
              <Button
                variant="contained"
                color="secondary"
                startIcon={<PhotoCamera />}
              >
                Use Camera
              </Button>

              {/* Aadhar Front */}
              <Typography variant="subtitle1" sx={{ mt: 2 }}>
                Aadhar Card (Front)
              </Typography>
              <Button
                component="label"
                variant="outlined"
                startIcon={<UploadFileIcon />}
              >
                Upload Aadhar Front
                <input
                  type="file"
                  hidden
                  onChange={(e) =>
                    handleFile("aadharFront", e.target.files[0])
                  }
                />
              </Button>
              {form.aadharFront && (
                <Typography variant="body2">
                  📂 {form.aadharFront.name}
                </Typography>
              )}
              <Button
                variant="contained"
                color="secondary"
                startIcon={<PhotoCamera />}
              >
                Use Camera
              </Button>

              {/* Aadhar Back */}
              <Typography variant="subtitle1" sx={{ mt: 2 }}>
                Aadhar Card (Back)
              </Typography>
              <Button
                component="label"
                variant="outlined"
                startIcon={<UploadFileIcon />}
              >
                Upload Aadhar Back
                <input
                  type="file"
                  hidden
                  onChange={(e) =>
                    handleFile("aadharBack", e.target.files[0])
                  }
                />
              </Button>
              {form.aadharBack && (
                <Typography variant="body2">
                  📂 {form.aadharBack.name}
                </Typography>
              )}
              <Button
                variant="contained"
                color="secondary"
                startIcon={<PhotoCamera />}
              >
                Use Camera
              </Button>
            </Box>
          </Grid>
        </Grid>

        {/* Submit Button */}
        <Box sx={{ textAlign: "center", mt: 4 }}>
          <Button
            type="submit"
            variant="contained"
            sx={{ bgcolor: "black", color: "white" }}
          >
            Submit Documents
          </Button>
        </Box>
      </form>
    </Box>
  );
}
